list.value:
IMPACKET=$(python3 -c "import impacket; print(impacket.__version__)" 2>&1);
LDAP3=$(python3 -c "import ldap3; print(ldap3.__version__)" 2>&1);
KRB5=$(python3 -c "import gssapi; print('gssapi_ok')" 2>&1);
PYASN1=$(python3 -c "import pyasn1; print('pyasn1_ok')" 2>&1);
PYCRYPTO=$(python3 -c "import Crypto; print('pycrypto_ok')" 2>&1);
TGT_CHECK=$(ls -la /tmp/krb5cc_* 2>&1);
NET_REACH=$(timeout 3 bash -c "echo >/dev/tcp/172.16.1.1/445" 2>&1 && echo "DC_445_OK" || echo "DC_445_FAIL");
PYTHON_PKGS=$(pip3 list 2>/dev/null | grep -iE "impacket|ldap|krb|kerberos|gssapi" 2>&1);
echo "=IMPACKET=$IMPACKET=LDAP3=$LDAP3=KRB5=$KRB5=PYASN1=$PYASN1=PYCRYPTO=$PYCRYPTO=TGT=$TGT_CHECK=NET=$NET_REACH=PKGS=$PYTHON_PKGS"
